-- Fix the Default Booking Confirmation template - properly close the hotel_bookings loop
UPDATE email_templates
SET content_template = '<p>Dear {{customer_first_name}} {{customer_last_name}},</p><p><br></p><p>Thank you for your booking! Please find your booking confirmation details below. If anything is incorrect, please let us know as soon as possible:</p><p><br></p><p>TOUR DETAILS: • Tour: {{tour_name}} • Location: {{tour_location}} • Tour Dates: {{tour_start_date}} - {{tour_end_date}} • Duration: {{tour_days}} days, {{tour_nights}} nights</p><p><br></p><p>PASSENGER INFORMATION: • Lead Passenger: {{customer_first_name}} {{customer_last_name}} • Email: {{customer_email}} • Phone: {{customer_phone}} • Total Passengers: {{booking_passenger_count}}{{#booking_passenger_2_name}} • Passenger 2: {{booking_passenger_2_name}}{{/booking_passenger_2_name}}{{#booking_passenger_3_name}} • Passenger 3: {{booking_passenger_3_name}}{{/booking_passenger_3_name}}</p><p><br></p><p>ACCOMMODATION:{{#hotel_bookings}} • {{hotel_name}}: {{hotel_check_in_date}} - {{hotel_check_out_date}}, {{hotel_room_type}}, {{hotel_bedding}} bed{{#hotel_room_upgrade}}, Upgrade: {{hotel_room_upgrade}}{{/hotel_room_upgrade}}{{/hotel_bookings}}</p><p><br></p>{{#booking_dietary_restrictions}}<p>DIETARY REQUIREMENTS: {{booking_dietary_restrictions}}</p><p><br></p>{{/booking_dietary_restrictions}}{{#booking_extra_requests}}<p>SPECIAL REQUESTS: {{booking_extra_requests}}</p><p><br></p>{{/booking_extra_requests}}<p>If you have any questions or need to make changes to your booking, please reply to this email and we''ll get back to you promptly.</p><p><br></p><p>Best regards, The Team</p>',
    updated_at = now()
WHERE type = 'booking_confirmation' 
  AND name = 'Default Booking Confirmation';